/* BTSeparator — visual divider atom (Figma 194:756)
 *
 * Single-token component: uses only border.primary (1px line).
 * Orientation: horizontal (default, full-width) | vertical (full-height).
 *
 * Usage:
 *   Horizontal: place inside a flex-col container — stretches to parent width.
 *   Vertical:   place inside a flex-row container — stretches to parent height.
 */

.bt-separator {
  flex-shrink: 0;
  background: var(--border-primary);
  border: none;
}

/* ── Horizontal ─────────────────────────────────────────────────────────── */

.bt-separator--horizontal {
  width: 100%;
  height: 1px;
}

/* ── Vertical ───────────────────────────────────────────────────────────── */

.bt-separator--vertical {
  width: 1px;
  height: 100%;
}

/**
 * BTSeparator — visual divider atom (Figma 194:756).
 *
 * Renders a 1px line using the border.primary token.
 * Orientation: 'horizontal' (default) | 'vertical'.
 *
 * @example
 * ```tsx
 * // Horizontal (default) — inside a flex-col container
 * <BTSeparator />
 *
 * // Vertical — inside a flex-row container with defined height
 * <BTSeparator orientation="vertical" />
 * ```
 */
import './BTSeparator.css';
import type { BTSeparatorProps } from './BTSeparator.types';

export function BTSeparator({ orientation = 'horizontal', className }: BTSeparatorProps) {
  const classes = ['bt-separator', `bt-separator--${orientation}`, className]
    .filter(Boolean)
    .join(' ');

  return (
    <div
      role="separator"
      aria-orientation={orientation}
      className={classes}
    />
  );
}

BTSeparator.displayName = 'BTSeparator';

// BTSeparator types — Figma source: node 194:756.

/** Orientation of the separator line. */
export type BTSeparatorOrientation = 'horizontal' | 'vertical';

export interface BTSeparatorProps {
  /**
   * Direction of the divider line.
   * @default 'horizontal'
   */
  orientation?: BTSeparatorOrientation;
  /** Additional CSS class names. */
  className?: string;
}
